mapper.select:
    /*AcenRcpMgmtMapper.getAcenRcpMgmtList*/

    SELECT
         REQ.REQUEST_KEY                                                        /*신청키*/
       , TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY         /*신청일자*/
       , REQ.RES_NO                                                             /*예약번호*/
       , CST.CSTMR_NAME AS CSTMR_NM                                             /*고객명*/
       , REQ.CSTMR_TYPE
       , (SELECT RATE_NM FROM MSP_RATE_MST
          WHERE RATE_CD = SAL.SOC_CODE
          AND SERVICE_TYPE = 'P' AND ROWNUM = 1)
          || '(' || SAL.SOC_CODE || ')' AS SOC_NM	                              /*요금제*/
       , FN_GET_CODENM('RCP9001', REQ.OPER_TYPE) AS OPER_NM                     /*업무구분*/
       , FN_GET_CODENM('RCP0006', REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NM   /*진행상태*/
       , FN_GET_CODENM('RCP0005', REQ.PSTATE) AS PSTATE_NM                      /*신청서상태*/
       , FN_GET_CODENM('RCP9032', DLV.DLVRY_TYPE) AS DLVRY_TYPE_NM              /*배송방법*/
       , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
          WHERE CD_GROUP_ID = 'AcenEvntGrp'
          AND DTL_CD = ACEN.EVNT_GRP_CD) AS ACEN_EVNT_GRP_NM                    /*시나리오*/
       , CASE ACEN.SUCC_YN WHEN 'Y' THEN '성공'
                           WHEN 'N' THEN '실패'
                           ELSE '진행중' END AS ACEN_STATUS                      /*성공여부*/
       , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP
          WHERE CD_GROUP_ID = 'AcenErrCd'
          AND DTL_CD = ACEN.RMK) AS ACEN_FAIL_RMK                               /*실패사유*/
       , REQ.MEMO AS REQUEST_MEMO                                               /*처리메모*/
       , DECODE(REQ.RVISN_ID, 'ACEN', REQ.RVISN_ID, FN_GET_USRNM(REQ.RVISN_ID)) AS RVISN_NM
       , TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM
       ,(SELECT COUNT(1)
         FROM CMN_GRP_CD_MST A
         WHERE A.GRP_ID = 'RCP0073'
         AND A.USG_YN = 'Y'
         AND A.CD_VAL = REQ.CNTPNT_SHOP_ID
         AND EXISTS (SELECT 1 FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP0074' AND CD_VAL = REQ.OPER_TYPE AND USG_YN = 'Y')
         AND EXISTS (SELECT 1 FROM CMN_USR_MST WHERE USR_ID = #{sessionUserId} AND KOS_ID IS NOT NULL)
        ) AS OSST_CHK       /* 직접개통 처리여부 추가 */
    FROM NMCP_ACEN_REQ@DL_MCP ACEN
       , MCP_REQUEST@DL_MCP REQ
       , MCP_REQUEST_CSTMR@DL_MCP CST
       , MCP_REQUEST_SALEINFO@DL_MCP SAL
       , MCP_REQUEST_DLVRY@DL_MCP DLV
    WHERE ACEN.REQUEST_KEY = REQ.REQUEST_KEY
      AND ACEN.REQUEST_KEY = CST.REQUEST_KEY
      AND ACEN.REQUEST_KEY = SAL.REQUEST_KEY
      AND ACEN.REQUEST_KEY = DLV.REQUEST_KEY
      /*신청일자필터*/

        AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{srchStrtDt},'YYYYMMDD') AND TO_DATE(#{srchEndDt},'YYYYMMDD') + 1

      /*업무구분필터*/

        AND REQ.OPER_TYPE = #{pOperType}

      /*구매유형필터*/

        AND REQ.REQ_BUY_TYPE = #{pReqBuyType}

      /*대리점필터*/

        AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})

      /*진행상태필터*/

        AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode}

      /*신청취소필터*/

        AND REQ.PSTATE = #{pPstate}

      /*시나리오필터*/

        AND ACEN.EVNT_GRP_CD = #{pAcenEvntGrp}

      /*성공여부필터*/

        AND ACEN.SUCC_YN = #{pSuccYn}

      /*실패사유필터*/

        AND ACEN.RMK = #{pAcenErrCd}

      /*모집경로필터*/

        AND REQ.ON_OFF_TYPE = #{pOnOffType}

      /*eSIM여부필터*/

        AND REQ.USIM_KINDS_CD = '09'

      /*검색구분필터-고객명*/

        AND CST.CSTMR_NAME LIKE #{pSearchName} || '%'

      /*검색구분필터-계약번호*/

        AND REQ.CONTRACT_NUM = #{pSearchName}

      /*검색구분필터-연락처*/

        AND (CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890')
             OR CST.CSTMR_TEL_FN || CST.CSTMR_TEL_MN || CST.CSTMR_TEL_RN = TRANSLATE(#{pSearchName},'1234567890-','1234567890'))

      /*검색구분필터-단말기일련번호*/

        AND REQ.REQ_PHONE_SN = #{pSearchName}

      /*검색구분필터-예약번호*/

        AND REQ.RES_NO = #{pSearchName}

      /*검색구분필터-요금제*/

        AND SAL.SOC_CODE IN (SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%')

      /*셀프개통 제외 필터*/

		AND REQ.ON_OFF_TYPE NOT IN ('5','7')

    ORDER BY REQ.REQUEST_KEY DESC

mapper.update:
/*AcenRcpMgmtMapper.updateAcenWithRty*/
UPDATE NMCP_ACEN_REQ@DL_MCP
SET EVNT_TYPE = #{rtyEvntType}
  , REQ_STATUS = 'N'
  , END_STATUS = 'N'
  , SUCC_YN = NULL
  , PRE_CHECK_YN = #{preCheckYn}
  , OPEN_YN = NULL
  , RMK = NULL
  , RVISN_ID = #{sessionUserId}
  , RVISN_DTTM = SYSDATE
  , RTY_ID = #{sessionUserId}
  , RTY_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
  , RTY_DTTM = SYSDATE
WHERE REQUEST_KEY = #{requestKey}

/*AcenRcpMgmtMapper.updateMcpRequestState*/
UPDATE MCP_REQUEST@DL_MCP
SET  RVISN_ID = #{sessionUserId}
    ,RVISN_DTTM = SYSDATE
    ,PSTATE = #{pstate}
    ,REQUEST_STATE_CODE = #{requestStateCode}
WHERE REQUEST_KEY = #{requestKey}
